-- Dumping structure for trigger optima_db.update_kontrak_totals_after_unit_update
SET @OLDTMP_SQL_MODE=@@SQL_MODE, SQL_MODE='ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION';
DELIMITER //
CREATE TRIGGER `update_kontrak_totals_after_unit_update` AFTER UPDATE ON `inventory_unit` FOR EACH ROW BEGIN
    -- Update old kontrak if changed
    IF OLD.kontrak_id IS NOT NULL AND (OLD.kontrak_id != NEW.kontrak_id OR NEW.kontrak_id IS NULL) THEN
        CALL update_kontrak_totals_proc(OLD.kontrak_id);
    END IF;
    
    -- Update new kontrak
    IF NEW.kontrak_id IS NOT NULL THEN
        CALL update_kontrak_totals_proc(NEW.kontrak_id);
    END IF;
END//
DELIMITER ;
SET SQL_MODE=@OLDTMP_SQL_MODE;

-- Removing temporary table and create final VIEW structure
DROP TABLE IF EXISTS `user_all_permissions`;
CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `user_all_permissions` AS select distinct `u`.`id` AS `user_id`,`u`.`username` AS `username`,`u`.`email` AS `email`,`u`.`first_name` AS `first_name`,`u`.`last_name` AS `last_name`,`d`.`name` AS `division_name`,`p`.`id` AS `permission_id`,`p`.`name` AS `permission_name`,`p`.`key` AS `permission_key`,`p`.`module` AS `module`,`p`.`category` AS `category`,'role' AS `source_type`,`r`.`name` AS `source_name`,`rp`.`granted` AS `granted` from (((((`users` `u` left join `user_roles` `ur` on(((`u`.`id` = `ur`.`user_id`) and (`ur`.`is_active` = 1)))) left join `roles` `r` on(((`ur`.`role_id` = `r`.`id`) and (`r`.`is_active` = 1)))) left join `role_permissions` `rp` on(((`r`.`id` = `rp`.`role_id`) and (`rp`.`granted` = 1)))) left join `permissions` `p` on(((`rp`.`permission_id` = `p`.`id`) and (`p`.`is_active` = 1)))) left join `divisions` `d` on((`u`.`division_id` = `d`.`id`))) where (`u`.`is_active` = 1) union all select distinct `u`.`id` AS `user_id`,`u`.`username` AS `username`,`u`.`email` AS `email`,`u`.`first_name` AS `first_name`,`u`.`last_name` AS `last_name`,`d`.`name` AS `division_name`,`p`.`id` AS `permission_id`,`p`.`name` AS `permission_name`,`p`.`key` AS `permission_key`,`p`.`module` AS `module`,`p`.`category` AS `category`,'direct' AS `source_type`,'Direct Assignment' AS `source_name`,`up`.`granted` AS `granted` from (((`users` `u` left join `user_permissions` `up` on(((`u`.`id` = `up`.`user_id`) and ((`up`.`expires_at` is null) or (`up`.`expires_at` > now()))))) left join `permissions` `p` on(((`up`.`permission_id` = `p`.`id`) and (`p`.`is_active` = 1)))) left join `divisions` `d` on((`u`.`division_id` = `d`.`id`))) where (`u`.`is_active` = 1);

